    // 3. If odd elements exist, Target EVEN is impossible (because the smallest odd element
    // cannot be made even via subtraction). We must check if Target ODD is achievable.

    // Check Target ODD feasibility:
    // If nums1[i] is odd, we use it directly (OK).
    // If nums1[i] is even, we must subtract an odd number nums1[j] such that nums1[i] - nums1[j] >= 1.
    // This requires nums1[i] > minOdd.
    for (const num of nums1) {
        if (num % 2 === 0) {
            // Current number is even. Must be convertible to odd.
            if (num <= minOdd) {
                // Cannot find an odd number to subtract resulting in a positive odd number.
                return false;
            }
        }
    }

    // All even numbers could be converted to odd, and odd numbers are already odd.
    return true;
}
